import { generateText, tool } from 'ai';
import { z } from 'zod';

const researchTool = tool({
  description: 'Research a topic',
  parameters: z.object({ query: z.string() }),
  execute: async ({ query }) => ({ result: `Researched: ${query}` })
});

function detectCoordinationFailure(toolCalls: any[]) {
  const toolUsage = new Map();
  const duplicates = [];

  for (const call of toolCalls) {
    const key = `${call.name}:${JSON.stringify(call.args)}`;
    if (toolUsage.has(key)) {
      duplicates.push({ tool: key, count: toolUsage.get(key) + 1 });
    }
    toolUsage.set(key, (toolUsage.get(key) || 0) + 1);
  }

  return duplicates.length > 0;
}

const result = await generateText({
  model: 'gpt-4o',
  tools: { researchTool },
  onToolCall: (call) => {
    if (detectCoordinationFailure(call)) {
      console.error('COORDINATION FAILURE: Duplicate tool calls detected');
    }
  }
});

