function validateAgentHandoff(prevState: any, newState: any) {
  const requiredKeys = ['task_id', 'current_step', 'dependencies'];
  const missing = requiredKeys.filter(key => !newState[key] || newState[key] !== prevState[key]);

  if (missing.length > 0) {
    throw new Error(`Context corruption detected: missing ${missing.join(', ')}`);
  }
  return true;
}

