function monitorStreamCollisions(streams: any[]) {
  const activeStreams = new Set();
  const collisions = [];

  streams.forEach((stream, index) => {
    const streamId = `agent-${index}`;
    if (activeStreams.has(streamId)) {
      collisions.push({ streamId, timestamp: Date.now(), error: 'Concurrent stream collision' });
    }
    activeStreams.add(streamId);
  });

  if (collisions.length > 0) {
    console.error('STREAM COLLISION:', collisions);
  }
}

