import { generateText } from 'ai';
import pino from 'pino';

const logger = pino();
const taskLocks = new Map<string, Promise<any>>();

class AgentCoordinator {
  static async executeWithLock(taskId: string, fn: () => Promise<any>) {
    if (taskLocks.has(taskId)) {
      await taskLocks.get(taskId);
    }

    const promise = fn();
    taskLocks.set(taskId, promise);

    try {
      return await promise;
    } finally {
      taskLocks.delete(taskId);
    }
  }
}

export async function coordinatedResearch(query: string) {
  return AgentCoordinator.executeWithLock(`research-${query}`, async () => {
    const result = await generateText({
      model: 'gpt-4o',
      tools: {
        research: tool({
          parameters: z.object({ q: z.string() }),
          execute: async ({ q }) => ({ data: `Result for ${q}` })
        })
      }
    });
    return result;
  });
}

import { generateObject, streamObject } from 'ai';
import { z } from 'zod';

const TaskHandoffSchema = z.object({
  task_id: z.string(),
  status: z.enum(['pending', 'in_progress', 'completed']),
  context: z.record(z.any()),
  next_agent: z.string(),
  timestamp: z.number()
});

type Handoff = z.infer<typeof TaskHandoffSchema>;

export async function agentHandoff(currentTask: Handoff) {
  const handoff = await generateObject({
    model: 'gpt-4o',
    schema: TaskHandoffSchema,
    prompt: `Complete this task handoff: ${JSON.stringify(currentTask)}`
  });

  // Validate before passing to next agent
  const validated = TaskHandoffSchema.parse(handoff);

  return validated;
}

export async function* multiAgentStream(initialTask: any) {
  let task = initialTask;

  while (task.status !== 'completed') {
    task = await agentHandoff(task);
    yield task;
  }
}

import { streamText } from 'ai';

class SequentialOrchestrator {
  private activeAgent: string | null = null;

  async runAgentSequentially(agentId: string, fn: () => Promise<any>) {
    if (this.activeAgent && this.activeAgent !== agentId) {
      throw new Error(`Agent ${agentId} cannot run while ${this.activeAgent} is active`);
    }

    this.activeAgent = agentId;
    try {
      return await fn();
    } finally {
      this.activeAgent = null;
    }
  }
}

const orchestrator = new SequentialOrchestrator();

export async function coordinatedAgentWorkflow() {
  const plannerResult = await orchestrator.runAgentSequentially('planner', () =>
    streamText({ model: 'gpt-4o', prompt: 'Create plan' })
  );

  const executorResult = await orchestrator.runAgentSequentially('executor', () =>
    streamText({ 
      model: 'gpt-4o', 
      prompt: `Execute: ${plannerResult.text}` 
    })
  );

  return executorResult;
}

